import React, { useCallback, useEffect, useRef } from 'react'
import { useCountdownStore } from './useCountDownStore'

function useCountdown() {
    const { initialSeconds, setIsRunning, setTimeLeft, timeLeft } = useCountdownStore((state) => state)
    const intervalRef = useRef(null)
    const timeLeftRef = useRef(timeLeft)
    console.log('timeLeftRef', timeLeftRef)
    console.log('timeLeft', timeLeft)
    function calculateTimeLeft() {
        console.log('timerRef', timeLeftRef.current)
        // if (time <= 1) {
        //     clearInterval(intervalRef)
        //     timeLeftRef.current = null
        //     setIsRunning(false)
        //     timeLeftRef.current = 0
        // } else {
        timeLeftRef.current = timeLeftRef.current - 1
        //}
    }

    useEffect(() => {
        setTimeLeft(timeLeftRef.current)
    }, [timeLeftRef.current])

    const start = useCallback(() => {
        setIsRunning(true)
        intervalRef.current = setInterval(() => {
            console.log('>>>>', timeLeftRef)
            calculateTimeLeft(timeLeftRef)
        }, 1000)
    }, [])

    const pause = useCallback(() => {
        clearInterval(intervalRef)
        intervalRef.current = null
        setIsRunning(false)
    }, [])

    const reset = useCallback(() => {
        clearInterval(intervalRef)
        intervalRef.current = null
        setIsRunning(false)
        setTimeLeft(initialSeconds)
    }, [initialSeconds])

    return { start, pause, reset }
}

export default useCountdown
